final:
module johnson_counter(
    input wire clk,
    input wire reset,
    output reg [4:0] obf_Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            obf_Q <= 5'b00000;
        end else begin
            obf_Q <= {obf_Q[3:0], ~obf_Q[4]};
        end
    end
endmodule
